const getPostEvent = (segId, evtName) => {
  const key = `${segId}|${evtName}`;
  if (POST_EVENT_DATA[key]) return POST_EVENT_DATA[key];
  let seed = 0;
  const str = segId+evtName;
  for (let i=0;i<str.length;i++) seed += str.charCodeAt(i)*(i+1);
  const rnd = (min,max) => min+Math.floor(((seed*9301+49297)%233280)/233280*(max-min));
  return { event:evtName, sku:"Monster Original 16oz", market:"Multiple Markets", attendance:rnd(8000,60000), social_impressions:rnd(800000,8000000), ugc_posts:rnd(2000,15000), earned_media_value:rnd(400000,3000000), scan_data:[{w:"Wk -2",lift:rnd(3,8)},{w:"Wk 0",lift:rnd(28,50)},{w:"Wk +1",lift:rnd(18,35)},{w:"Wk +2",lift:rnd(10,22)},{w:"Wk +4",lift:rnd(5,14)},{w:"Wk +8",lift:rnd(2,7)}], retailer_perf:[{r:"Walmart",base:rnd(900,3500),event:rnd(1200,5000),lift:rnd(28,55)},{r:"Target",base:rnd(700,2500),event:rnd(900,3800),lift:rnd(25,50)},{r:"7-Eleven",base:rnd(1500,5000),event:rnd(2100,7000),lift:rnd(30,55)}], new_buyers_pct:rnd(15,38), repeat_rate:rnd(20,35), nps:rnd(58,80), brand_health_lift:`+${rnd(4,13)}pts aided awareness`, top_content:`Event highlight reel \u2014 ${rnd(400,2400)}K views`, key_win:"Community co-creation approach drove outsized earned media vs. traditional sponsorship", key_miss:"Field execution compliance below 80% in 2 of 4 target markets", recommendation:"Increase field team size by 40% for markets >25K attendance" };
};

