const SENSITIVITY = (roi_base) => {
  const base = parseFloat(roi_base);
  return {
    bull: { att:"+30%", social:"+50%", scan:"+52%", roi:(base*1.38).toFixed(1)+"x", note:"Activation goes viral, artist collab drives massive UGC, retailer compliance 95%+" },
    base: { att:"As modeled", social:"As modeled", scan:"As modeled", roi:roi_base, note:"Plan executes as designed with normal variance in attendance and retailer compliance" },
    bear: { att:"-25%", social:"-30%", scan:"-18%", roi:(base*0.68).toFixed(1)+"x", note:"Weather event, competing activation, or retail compliance below 70% in key markets" },
  };
};

